function uid() { return Date.now().toString(36) + Math.random().toString(36).slice(2, 8); }

function periodKey(recurrence, ts = Date.now()) {
  const d = new Date(ts);
  if (recurrence === "daily") return d.toISOString().slice(0, 10);
  if (recurrence === "weekly") {
    const onejan = new Date(d.getFullYear(), 0, 1);
    const week = Math.ceil(((d - onejan) / 86400000 + onejan.getDay() + 1) / 7);
    return d.getFullYear() + "-W" + week;
  }
  return "once";
}

function fmtDate(ts) {
  const d = new Date(ts);
  return d.toLocaleDateString("he-IL") + " " + d.toLocaleTimeString("he-IL", { hour: "2-digit", minute: "2-digit" });
}

function cn(...a) { return a.filter(Boolean).join(" "); }

async function storageGet(key, shared) {
  try {
    const r = await window.storage.get(key, shared);
    return r ? JSON.parse(r.value) : null;
  } catch (e) { return null; }
}
async function storageSet(key, value, shared) {
  try { await window.storage.set(key, JSON.stringify(value), shared); return true; }
  catch (e) { console.error("storage set failed", key, e); return false; }
}

function exportCSV(filename, headers, rows) {
  const esc = (c) => `"${String(c ?? "").replace(/"/g, '""')}"`;
  const csv = [headers.map(esc).join(","), ...rows.map((r) => r.map(esc).join(","))].join("\r\n");
  const blob = new Blob(["\uFEFF" + csv], { type: "text/csv;charset=utf-8;" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = filename; document.body.appendChild(a); a.click();
  document.body.removeChild(a); URL.revokeObjectURL(url);
}

function resizeImage(file) {
  return new Promise((resolve, reject) => {
    if (!file.type.startsWith("image/")) { reject(new Error("not an image")); return; }
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new window.Image();
      img.onload = () => {
        const maxW = 480;
        const scale = Math.min(1, maxW / img.width);
        const w = Math.max(1, Math.round(img.width * scale));
        const h = Math.max(1, Math.round(img.height * scale));
        const canvas = document.createElement("canvas");
        canvas.width = w; canvas.height = h;
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0, w, h);
        resolve(canvas.toDataURL("image/jpeg", 0.62));
      };
      img.onerror = () => reject(new Error("image load failed"));
      img.src = e.target.result;
    };
    reader.onerror = () => reject(new Error("file read failed"));
    reader.readAsDataURL(file);
  });
}

function printReport(t, inventory, projects, routineTasks, period) {
  const now = Date.now();
  const days = period === "week" ? 7 : 30;
  const cutoff = now - days * 86400000;
  const items = Object.entries(inventory);
  const lowStock = items.filter(([, v]) => v.c < v.m);
  const isDone = (p) => p.tasks.length > 0 && p.tasks.every((tk) => !!tk.completedAt);
  const activeProj = projects.filter((p) => !isDone(p));
  const doneProj = projects.filter(isDone);
  const html = `<!DOCTYPE html><html dir="rtl" lang="he">
<head><meta charset="utf-8"><title>${t.print_report} — ${new Date().toLocaleDateString("he-IL")}</title>
<style>
body{font-family:Arial,sans-serif;margin:32px;color:#111;font-size:13px;direction:rtl}
h1{font-size:22px;border-bottom:2px solid #111;padding-bottom:8px}
h2{font-size:16px;margin-top:24px;color:#333;border-bottom:1px solid #ddd;padding-bottom:4px}
table{width:100%;border-collapse:collapse;margin-top:8px}
th{background:#eee;padding:6px 10px;text-align:right;font-size:12px}
td{padding:5px 10px;border-bottom:1px solid #f0f0f0;font-size:12px}
.badge{display:inline-block;padding:2px 6px;border-radius:4px;font-size:11px}
.red{background:#fde;color:#b00} .yellow{background:#ffefc0;color:#885} .green{background:#e0fde0;color:#070}
@media print{body{margin:12px}}
</style></head><body>
<h1>${t.appName} — ${t.print_report}</h1>
<p style="color:#555">${new Date().toLocaleDateString("he-IL")} | ${period === "week" ? t.period_week : t.period_month}</p>
<h2>${t.kpi_low_stock} (${lowStock.length})</h2>
<table><tr><th>${t.item_name}</th><th>${t.item_current}</th><th>${t.item_minimum}</th></tr>
${lowStock.map(([n,v])=>`<tr><td>${n}</td><td><span class="badge ${v.c<0?"red":"yellow"}">${v.c}</span></td><td>${v.m}</td></tr>`).join("")}
</table>
<h2>${t.kpi_active_projects} (${activeProj.length})</h2>
<table><tr><th>${t.project_name}</th><th>${t.client_name}</th><th>${t.order_num}</th><th>${t.target_date}</th><th>${t.progress}</th></tr>
${activeProj.map(p=>{
  const done=p.tasks.filter(tk=>!!tk.completedAt).length;
  return `<tr><td>${p.title}</td><td>${p.client||""}</td><td>${p.orderNum||""}</td><td>${p.targetDate||""}</td><td>${done}/${p.tasks.length}</td></tr>`;
}).join("")}
</table>
<h2>${t.kpi_done_projects} (${doneProj.length})</h2>
<table><tr><th>${t.project_name}</th><th>${t.client_name}</th><th>${t.order_num}</th><th>${t.created_by}</th></tr>
${doneProj.map(p=>`<tr><td>${p.title}</td><td>${p.client||""}</td><td>${p.orderNum||""}</td><td>${p.createdBy}</td></tr>`).join("")}
</table>
</body></html>`;
  const w = window.open("", "_blank");
  if (w) { w.document.write(html); w.document.close(); setTimeout(() => w.print(), 400); }
}

function whatsappLowStock(t, inventory) {
  const low = Object.entries(inventory).filter(([,v]) => v.c < v.m);
  if (!low.length) return;
  const lines = low.map(([n,v]) => `• ${n}: ${v.c} (מינ׳ ${v.m})`).join("\n");
  const msg = encodeURIComponent(`${t.low_stock_msg_intro}\n\n${lines}\n\n${new Date().toLocaleDateString("he-IL")}`);
  window.open(`https://wa.me/?text=${msg}`, "_blank");
}

async function translateText(text, sourceLang) {
  const targetName = sourceLang === "he" ? "Arabic" : "Hebrew";
  try {
    const res = await fetch("https://api.anthropic.com/v1/messages", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        model: "claude-sonnet-4-6",
        max_tokens: 400,
        messages: [{
          role: "user",
          content: `Translate the following short workplace note to ${targetName}. Reply with ONLY the translation, no quotes, no explanation:\n\n${text}`,
        }],
      }),
    });
    const data = await res.json();
    const block = data && data.content && data.content.find((b) => b.type === "text");
    return block ? block.text.trim() : null;
  } catch (e) { console.error("translate failed", e); return null; }
}


