function Btn({ children, onClick, variant = "default", size = "md", className = "", disabled, type = "button", title, style: extraStyle }) {
  const base = "fbtn inline-flex items-center justify-center gap-2 rounded-lg font-semibold disabled:opacity-35 disabled:cursor-not-allowed";
  const sizes = { xs: "px-2 py-1 text-xs", sm: "px-3 py-1.5 text-xs", md: "px-4 py-2 text-sm", lg: "px-5 py-2.5 text-sm" };
  const styleMap = {
    default: { background: "linear-gradient(135deg,#1FC8C2,#14A09B)", color: "#fff", boxShadow: "0 2px 8px #1FC8C240" },
    danger:  { background: "linear-gradient(135deg,#E5484D,#B53035)", color: "#fff" },
    outline: { background: "transparent", borderColor: "#2C3A46", color: "#C8D3DC", border: "1px solid #2C3A46" },
    ghost:   { background: "transparent", borderColor: "#1E2730", color: "#8B96A3", border: "1px solid #1E2730" },
    subtle:  { background: "#1B2128", color: "#C8D3DC" },
  };
  const cls = variant === "outline" || variant === "ghost" ? "" : "";
  return (
    <button type={type} title={title} disabled={disabled} onClick={onClick}
      className={cn(base, sizes[size], cls, className)} style={{ ...styleMap[variant], ...extraStyle }}>
      {children}
    </button>
  );
}

