function LoginScreen({ lang, setLang, onEnter, profiles }) {
  const t = STR[lang];
  const [name, setName] = useState("");
  const [role, setRole] = useState("worker");
  const [showCode, setShowCode] = useState(false);
  const [code, setCode] = useState("");
  const [codeError, setCodeError] = useState(false);

  // Try URL hash auto-login on mount
  useEffect(() => {
    const hash = window.location.hash;
    const m = hash.match(/#uid=([^&]+)/);
    if (m && profiles && profiles.length > 0) {
      const profile = profiles.find((p) => p.id === m[1]);
      if (profile) { onEnter({ name: profile.name, role: profile.role, profile }); }
    }
  }, [profiles]);

  const tryCode = () => {
    const profile = (profiles || []).find((p) => p.code === code.trim().toUpperCase());
    if (profile) { onEnter({ name: profile.name, role: profile.role, profile }); }
    else { setCodeError(true); setTimeout(() => setCodeError(false), 2000); }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-5" style={{ background: "radial-gradient(circle at 50% 0%, #1B2128, #11151A 60%)" }}>
      <div className="w-full max-w-sm">
        <div className="flex justify-center mb-6">
          <div className="plate riv p-4 flex items-center gap-3" style={{ borderColor: "#1FC8C255" }}>
            <Factory size={26} color="#1FC8C2" />
            <Wrench size={20} color="#3E7CB1" />
          </div>
        </div>
        <h1 className="text-center text-2xl font-bold mb-1">{t.appName}</h1>
        <p className="text-center text-sm mb-7" style={{ color: "#8B96A3" }}>{t.login_sub}</p>

        {showCode ? (
          <div className="plate riv p-5 space-y-4">
            <Field label={t.have_code}>
              <input className={inputCls} style={{ ...inputStyle, borderColor: codeError ? "#E5484D" : "#2C353F" }}
                value={code} onChange={(e) => setCode(e.target.value.toUpperCase())}
                onKeyDown={(e) => e.key === "Enter" && tryCode()}
                placeholder={t.enter_code} autoFocus />
              {codeError && <span className="text-xs" style={{ color: "#E5484D" }}>{t.code_not_found}</span>}
            </Field>
            <Btn className="w-full" onClick={tryCode} disabled={!code.trim()}><ShieldCheck size={14} />{t.start}</Btn>
            <button onClick={() => setShowCode(false)} className="w-full text-xs text-center" style={{ color: "#8B96A3" }}>{t.or_login_manually}</button>
          </div>
        ) : (
          <div className="plate riv p-5 space-y-4">
            <button onClick={() => setShowCode(true)} className="w-full flex items-center justify-center gap-2 rounded-md py-2.5 text-sm font-medium border"
              style={{ borderColor: "#1FC8C255", color: "#1FC8C2", background: "#1FC8C210" }}>
              <ShieldCheck size={16} />{t.have_code}
            </button>

            <div className="flex items-center gap-2">
              <div style={{ flex: 1, height: 1, background: "#2C353F" }} />
              <span className="text-xs" style={{ color: "#4a5560" }}>{t.or_login_manually}</span>
              <div style={{ flex: 1, height: 1, background: "#2C353F" }} />
            </div>

            <Field label={t.login_name}>
              <input className={inputCls} style={inputStyle} value={name} onChange={(e) => setName(e.target.value)}
                placeholder={t.login_name_placeholder} />
            </Field>

            <Field label={t.login_role}>
              <div className="grid grid-cols-3 gap-2">
                {[["manager","#1FC8C2"], ["warehouse","#E8B339"], ["worker","#3E7CB1"]].map(([r, color]) => (
                  <button key={r} onClick={() => setRole(r)} className="fbtn rounded-md py-2 text-xs font-medium border"
                    style={{ background: role === r ? color + "22" : "#11151A", borderColor: role === r ? color : "#2C353F", color: role === r ? color : "#8B96A3" }}>
                    {t["role_" + r] || r}
                  </button>
                ))}
              </div>
            </Field>

            <Field label={t.login_lang}>
              <div className="grid grid-cols-2 gap-2">
                {[["he", "עברית"], ["ar", "العربية"]].map(([l, label]) => (
                  <button key={l} onClick={() => setLang(l)} className="fbtn rounded-md py-2 text-sm font-medium border"
                    style={{ background: lang === l ? "#222A33" : "#11151A", borderColor: lang === l ? "#E9EDF1" : "#2C353F", color: "#E9EDF1" }}>
                    {label}
                  </button>
                ))}
              </div>
            </Field>

            <Btn className="w-full mt-2" size="lg" disabled={!name.trim()} onClick={() => onEnter({ name: name.trim(), role, profile: null })}>
              {t.start}
            </Btn>
          </div>
        )}
      </div>
    </div>
  );
}

